<?php
// init.php - Script de inicialização da aplicação

if (!defined('SPOT_MASTER_INIT')) {
    die("Acesso direto não permitido.");
}

use App\Database;

function initialize_system() {
    try {
        $pdo = Database::getInstance();

        // Este texto é um ficheiro MP3 silencioso de 1 segundo, codificado em Base64.
        $silentMp3Base64 = '';
        
        $closingAnnouncements = [
            'Fecho - 15 minutos' => 'silent_15.mp3',
            'Fecho - 10 minutos' => 'silent_10.mp3',
            'Fecho - 5 minutos' => 'silent_5.mp3',
            'Fecho - Parque Fechado' => 'silent_closed.mp3'
        ];

        echo "\n";

        foreach ($closingAnnouncements as $title => $placeholderFile) {
            $stmt = $pdo->prepare("SELECT id FROM announcements WHERE title = ?");
            $stmt->execute([$title]);

            if ($stmt->fetch() === false) {
                echo "\n";
                
                $filePath = __DIR__ . '/public/uploads/' . $placeholderFile;
                
                // Cria um ficheiro MP3 silencioso verdadeiro se não existir
                if (!file_exists($filePath)) {
                    file_put_contents($filePath, base64_decode($silentMp3Base64));
                }

                $insertStmt = $pdo->prepare("INSERT INTO announcements (title, file_path, duration_seconds) VALUES (?, ?, ?)");
                // O nosso MP3 silencioso tem 1 segundo de duração
                $insertStmt->execute([$title, $placeholderFile, 1]);
            }
        }
        echo "\n";

    } catch (Exception $e) {
        error_log("Erro durante a inicializacao do Spot Master: " . $e->getMessage());
    }
}

// Executa a função
initialize_system();